// Initialize GPT-Image polling
const item = $input.item;

return [{
  json: {
    taskId: item.json.data.taskId,
    attempt: 0,
    maxAttempts: 20,  // 20 attempts × 25 seconds = 8.3 minutes max
    status: 'pending',
    pollType: 'gpt-image',
    ...item.json
  }
}];

// Process GPT-Image status
const item = $input.item;
const attempt = $('Init GPT Polling').item.json.attempt || 0;
const maxAttempts = $('Init GPT Polling').item.json.maxAttempts || 20;

const status = item.json.data?.status || item.json.status || 'processing';
const isComplete = status === 'completed' || status === 'SUCCESS' || status === 'done';
const resultUrls = item.json.data?.response?.resultUrls || [];

return [{
  json: {
    ...item.json,
    taskId: $('Init GPT Polling').item.json.taskId,
    attempt: attempt + 1,
    maxAttempts: maxAttempts,
    status: status,
    isComplete: isComplete,
    resultUrls: resultUrls,
    shouldRetry: !isComplete && (attempt + 1) < maxAttempts,
    pollType: 'gpt-image'
  }
}];

// Initialize Veo polling
const item = $input.item;

return [{
  json: {
    taskId: item.json.data.taskId,
    attempt: 0,
    maxAttempts: 24,  // 24 attempts × 25 seconds = 10 minutes max
    status: 'pending',
    pollType: 'veo',
    ...item.json
  }
}];

// Process Veo status with actual KIE response structure
const item = $input.item;
const attempt = $('Init Veo Polling').item.json.attempt || 0;
const maxAttempts = $('Init Veo Polling').item.json.maxAttempts || 24;

// Parse actual KIE API response structure
const responseCode = item.json.code || 0;
const responseMsg = item.json.msg || '';
const responseData = item.json.data || {};
const successFlag = responseData.successFlag || 0;
const errorCode = responseData.errorCode || null;
const errorMessage = responseData.errorMessage || null;

// Determine completion status
let isComplete = false;
let isFatalError = false;
let shouldRetry = false;
let videoUrl = null;
let errorType = null;

if (responseCode === 200 && successFlag === 1) {
  // Success - video generated
  isComplete = true;
  videoUrl = responseData.response?.resultUrls?.[0] || null;
} else if (responseCode === 200 && successFlag === 0) {
  // Still processing - no error but not complete
  shouldRetry = (attempt + 1) < maxAttempts;
} else if (responseCode === 400) {
  // Client error - content policy violation
  isFatalError = true;
  errorType = 'content_violation';
} else if (responseCode === 422) {
  // Fallback failed
  isFatalError = true;
  errorType = 'fallback_failed';
} else if (responseCode === 501) {
  // Generation failed
  isFatalError = true;
  errorType = 'generation_failed';
} else if (responseCode === 500) {
  // Server error - can retry
  errorType = 'server_error';
  shouldRetry = (attempt + 1) < maxAttempts;
} else if (errorCode !== null) {
  // Has error code - fatal
  isFatalError = true;
  errorType = 'api_error';
} else {
  // Still processing
  shouldRetry = (attempt + 1) < maxAttempts;
}

return [{
  json: {
    ...item.json,
    taskId: $('Init Veo Polling').item.json.taskId,
    attempt: attempt + 1,
    maxAttempts: maxAttempts,
    responseCode: responseCode,
    responseMsg: responseMsg,
    successFlag: successFlag,
    errorCode: errorCode,
    errorMessage: errorMessage,
    isComplete: isComplete,
    isFatalError: isFatalError,
    videoUrl: videoUrl,
    shouldRetry: !isComplete && !isFatalError && shouldRetry,
    errorType: errorType,
    resolution: responseData.response?.resolution || null,
    seeds: responseData.response?.seeds || null,
    pollType: 'veo'
  }
}];

// Video generation complete - using actual response structure
const item = $input.item;

return [{
  json: {
    status: 'success',
    videoUrl: item.json.videoUrl,
    taskId: item.json.taskId,
    attempts: item.json.attempt,
    resolution: item.json.resolution,
    seeds: item.json.seeds,
    successFlag: item.json.successFlag,
    message: '✅ Veo video generated successfully!'
  }
}];

// Timeout - max attempts reached
const item = $input.item;

return [{
  json: {
    status: 'timeout',
    error: `⏱️ Video generation timed out after ${item.json.attempt} attempts (${Math.round(item.json.attempt * 25 / 60)} minutes)`,
    lastResponseCode: item.json.responseCode,
    lastResponseMsg: item.json.responseMsg,
    taskId: item.json.taskId
  }
}];


`
## 📊 **Error Handling Flow:**

Check Veo Status
    ↓
Process Veo Status → Analyzes response code
    ↓
Check Veo Complete (Switch with 3 outputs):
    ├─ Success (code 200) → Format Veo Success
    ├─ Fatal Error (400, 422, 501) → Format Veo Fatal Error
    ├─ Retry (500 or no code) → Wait 25s (Veo) → Loop back
    └─ Timeout (max attempts) → Format Veo Timeout

`

