const item = $input.item;

const errorMessages = {
  'content_violation': '❌ Content Policy Violation: Your prompt or image was flagged.',
  'fallback_failed': '❌ Generation Failed: Request was rejected.',
  'generation_failed': '❌ Generation Failed: Video generation task failed.',
  'api_error': '❌ API Error: ' + (item.json.errorMessage || 'Unknown error'),
  'unknown_error': '❌ Unknown Error: An unexpected error occurred.'
};

const userMessage = errorMessages[item.json.errorType] || errorMessages['unknown_error'];

return [{
  json: {
    status: 'fatal_error',
    error: userMessage,
    errorType: item.json.errorType,
    errorCode: item.json.errorCode || item.json.responseCode,
    errorMessage: item.json.errorMessage || item.json.responseMsg,
    taskId: item.json.taskId,
    attempts: item.json.attempt
  }
}];
